import sys
import math

def solve() -> None:
    it = iter(sys.stdin.read().strip().split())
    t = int(next(it))
    out_lines = []
    for _ in range(t):
        n = int(next(it))
        a = [int(next(it)) for _ in range(n)]

        cnt = [0] * 30
        for v in a:
            b = 0
            while v:
                if v & 1:
                    cnt[b] += 1
                v >>= 1
                b += 1

        g = 0
        for c in cnt:
            if c:
                g = math.gcd(g, c)

        if g == 0:                     # all numbers are zero
            ans = list(range(1, n + 1))
        else:
            ans = [k for k in range(1, n + 1) if g % k == 0]

        out_lines.append(' '.join(map(str, ans)))
    sys.stdout.write('\n'.join(out_lines))

