import sys

def solve() -> None:
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    t = int(next(it))
    out_lines = []
    for _ in range(t):
        x1 = int(next(it)); p1 = int(next(it))
        x2 = int(next(it)); p2 = int(next(it))

        d1 = len(str(x1))
        d2 = len(str(x2))

        len1 = d1 + p1
        len2 = d2 + p2

        if len1 < len2:
            out_lines.append('<')
            continue
        if len1 > len2:
            out_lines.append('>')
            continue

        # same total length
        if p1 > p2:
            # p1-p2 <= 7, safe to compute
            x1 *= 10 ** (p1 - p2)
        elif p2 > p1:
            x2 *= 10 ** (p2 - p1)

        if x1 < x2:
            out_lines.append('<')
        elif x1 > x2:
            out_lines.append('>')
        else:
            out_lines.append('=')

    sys.stdout.write('\n'.join(out_lines))

